import { AppSidebar } from '@/components/dashboard/AppSidebar'

export default function DashboardLayout({
  children,
}: {
  children: React.ReactNode
}) {
  return (
    <div className="min-h-screen bg-[#09090b] flex">
      <AppSidebar />
      <main className="flex-1 min-w-0 overflow-x-hidden">{children}</main>
    </div>
  )
}

'use client'

import { useEffect, useState, useCallback } from 'react'
import Link from 'next/link'
import {
  Play,
  RefreshCw,
  Clock,
  Sparkles,
  FolderOpen,
  CheckCircle,
  Building2,
} from 'lucide-react'
import { formatDistanceToNow } from 'date-fns'
import { toast } from 'sonner'

interface DashboardData {
  recentLogs: any[]
  pendingCount: number
  latestRun: any
  hasBrand: boolean
}

const quickLinks = [
  {
    href: '/content-studio/generate',
    label: 'Generate & Copy',
    description: 'Multi-platform content with one-click copy',
    icon: Sparkles,
  },
  {
    href: '/content-studio/packages',
    label: 'Saved Packages',
    description: 'Browse and reuse past generations',
    icon: FolderOpen,
  },
  {
    href: '/content-studio/approvals',
    label: 'Agent Approvals',
    description: 'Review proposals from planning cycles',
    icon: CheckCircle,
  },
]

export default function TekMarketingDashboard() {
  const [data, setData] = useState<DashboardData | null>(null)
  const [isRunningCycle, setIsRunningCycle] = useState(false)
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date())

  const loadData = useCallback(async () => {
    try {
      const res = await fetch('/api/dashboard/activity')
      if (res.ok) {
        const realData = await res.json()
        setData(realData)
        setLastUpdated(new Date())
      }
    } catch {
      // keep previous data on transient failures
    }
  }, [])

  async function runPlanningCycle() {
    setIsRunningCycle(true)
    try {
      const res = await fetch('/api/agent/run', { method: 'POST' })
      const result = await res.json()

      if (!res.ok) throw new Error(result.error || 'Failed to run cycle')

      toast.success('Planning cycle completed!', {
        description: `${result.proposalsCreated || 0} new proposals created.`,
        duration: 6000,
      })

      await loadData()
    } catch (err: unknown) {
      const message = err instanceof Error ? err.message : 'Unknown error'
      toast.error('Planning cycle failed', { description: message })
    } finally {
      setIsRunningCycle(false)
    }
  }

  useEffect(() => {
    loadData()

    const interval = setInterval(() => {
      if (!isRunningCycle) {
        loadData()
        setLastUpdated(new Date())
      }
    }, 25000)

    return () => clearInterval(interval)
  }, [isRunningCycle, loadData])

  if (!data) {
    return (
      <div className="max-w-7xl mx-auto px-8 py-8">
        <div className="flex items-center gap-3 text-[#71717a]">
          <RefreshCw className="w-4 h-4 animate-spin" /> Loading agent dashboard...
        </div>
      </div>
    )
  }

  const lastRunTime = data.latestRun
    ? formatDistanceToNow(new Date(data.latestRun.startedAt), { addSuffix: true })
    : 'never'

  return (
    <div className="max-w-7xl mx-auto px-8 py-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <div className="text-[10px] uppercase tracking-[2px] text-[#71717a] mb-1">Dashboard</div>
          <div className="flex items-center gap-3">
            <h1 className="text-3xl font-semibold tracking-[-1px]">Marketing Command Center</h1>
            <div className="px-2.5 py-1 rounded-full bg-emerald-500/10 text-emerald-400 text-[10px] font-medium tracking-widest flex items-center gap-1.5 border border-emerald-500/20">
              <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" />
              LIVE
            </div>
          </div>
          <div className="text-[#71717a] text-sm mt-1">
            Last active {lastRunTime} · Updated {formatDistanceToNow(lastUpdated, { addSuffix: true })}
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button
            onClick={() => loadData()}
            className="btn btn-ghost h-10 px-4 text-xs border border-[#27272a] hover:border-[#3f3f46]"
          >
            <RefreshCw className="w-3.5 h-3.5" />
            Refresh
          </button>

          <button
            onClick={runPlanningCycle}
            disabled={isRunningCycle || !data.hasBrand}
            className="btn btn-primary h-10 px-6 flex items-center gap-2 text-sm font-medium disabled:opacity-70"
          >
            {isRunningCycle ? (
              <>
                <RefreshCw className="w-4 h-4 animate-spin" />
                Running...
              </>
            ) : (
              <>
                <Play className="w-4 h-4" />
                Run Planning Cycle
              </>
            )}
          </button>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        <div className="card p-5">
          <div className="text-xs uppercase tracking-[1.5px] text-[#71717a] mb-2">Pending Your Review</div>
          <div className="text-4xl font-semibold tracking-tight tabular-nums">{data.pendingCount}</div>
          <div className="text-xs text-[#52525b] mt-1">drafts waiting for approval</div>
        </div>

        <div className="card p-5">
          <div className="text-xs uppercase tracking-[1.5px] text-[#71717a] mb-2">Recent Agent Activity</div>
          <div className="text-4xl font-semibold tracking-tight tabular-nums">{data.recentLogs.length}</div>
          <div className="text-xs text-[#52525b] mt-1">logged decisions & generations</div>
        </div>

        <div className="card p-5">
          <div className="text-xs uppercase tracking-[1.5px] text-[#71717a] mb-2">Last Strategy Run</div>
          <div className="text-4xl font-semibold tracking-tight tabular-nums">{data.latestRun ? '1' : '—'}</div>
          <div className="text-xs text-[#52525b] mt-1">
            {data.latestRun ? lastRunTime : 'No runs recorded yet'}
          </div>
          {data.latestRun?.summary && (
            <div className="mt-2 text-[11px] text-[#a1a1aa] line-clamp-2">
              {data.latestRun.summary}
            </div>
          )}
        </div>

        <div className="card p-5">
          <div className="text-xs uppercase tracking-[1.5px] text-[#71717a] mb-2">This Week Performance</div>
          <div className="flex items-baseline gap-2">
            <div className="text-4xl font-semibold tracking-tight tabular-nums">—</div>
            <div className="text-emerald-400 text-sm">+0%</div>
          </div>
          <div className="text-xs text-[#52525b] mt-1">Performance data unlocks after publishing</div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6">
        <div className="lg:col-span-7">
          <div className="flex items-center justify-between mb-3 px-1">
            <div>
              <div className="font-semibold text-xl tracking-tight">Agent Activity Feed</div>
              <div className="text-sm text-[#71717a]">Transparent record of every decision and output</div>
            </div>
            <Link href="/content-studio/activity" className="text-sm text-[#3b82f6] hover:underline">
              Full history →
            </Link>
          </div>

          <div className="card p-2">
            {data.recentLogs.length > 0 ? (
              <div className="divide-y divide-[#27272a]">
                {data.recentLogs.map((log: any) => (
                  <ActivityItem key={log.id} log={log} />
                ))}
              </div>
            ) : (
              <div className="p-12 text-center">
                <Clock className="w-8 h-8 mx-auto text-[#3f3f46] mb-4" />
                <div className="text-[#a1a1aa] font-medium">The agent hasn&apos;t run yet</div>
                <p className="text-sm text-[#52525b] max-w-xs mx-auto mt-2">
                  Set up a business profile, then run your first planning cycle to populate the feed.
                </p>
                {!data.hasBrand && (
                  <Link href="/businesses/new" className="btn btn-primary mt-4 inline-flex">
                    <Building2 className="w-4 h-4" />
                    Set Up Business
                  </Link>
                )}
              </div>
            )}
          </div>
        </div>

        <div className="lg:col-span-5 space-y-6">
          <div className="card p-6">
            <div className="font-medium text-sm tracking-tight mb-4">Quick Actions</div>
            <div className="space-y-2">
              {quickLinks.map((link) => {
                const Icon = link.icon
                return (
                  <Link
                    key={link.href}
                    href={link.href}
                    className="flex items-center gap-3 p-3 rounded-xl border border-[#27272a] hover:border-[#3f3f46] hover:bg-[#111113] transition-colors group"
                  >
                    <div className="w-9 h-9 rounded-lg bg-blue-500/10 flex items-center justify-center shrink-0">
                      <Icon className="w-4 h-4 text-blue-400" />
                    </div>
                    <div className="min-w-0">
                      <div className="text-sm font-medium group-hover:text-white transition-colors">
                        {link.label}
                      </div>
                      <div className="text-xs text-[#52525b] truncate">{link.description}</div>
                    </div>
                  </Link>
                )
              })}
            </div>
          </div>

          <div className="card p-6">
            <div className="flex items-center justify-between mb-3">
              <div className="font-medium text-sm tracking-tight">Needs Your Review</div>
              <Link href="/content-studio/approvals" className="text-xs text-[#3b82f6]">
                Open queue →
              </Link>
            </div>

            {data.pendingCount > 0 ? (
              <div className="text-sm">
                <span className="font-semibold text-[#f4f4f5]">{data.pendingCount}</span> pieces of
                content are ready for your approval.
              </div>
            ) : (
              <div className="text-sm text-[#52525b]">
                When the agent has new proposals, they will appear here with full reasoning.
              </div>
            )}
          </div>

          <div className="card p-6">
            <div className="text-sm font-medium tracking-tight mb-2">Scheduled Runs</div>
            <div className="text-[#a1a1aa] text-sm mb-3">
              Daily strategy loop at 07:00 UTC via Inngest (configure in production).
            </div>
            <button
              onClick={runPlanningCycle}
              disabled={isRunningCycle || !data.hasBrand}
              className="w-full btn btn-secondary h-10 text-sm flex items-center justify-center gap-2 disabled:opacity-70"
            >
              <Play className="w-4 h-4" />
              Trigger Manual Cycle
            </button>
          </div>
        </div>
      </div>

      {!data.hasBrand && (
        <div className="mt-8 p-6 border border-[#27272a] rounded-3xl bg-[#111113] flex items-center justify-between">
          <div>
            <div className="font-semibold">The agent has no brand context yet.</div>
            <div className="text-sm text-[#71717a]">Without it, every recommendation will be generic.</div>
          </div>
          <Link href="/businesses" className="btn btn-primary whitespace-nowrap">
            Set Up Business Profile →
          </Link>
        </div>
      )}
    </div>
  )
}

function ActivityItem({ log }: { log: any }) {
  const time = formatDistanceToNow(new Date(log.timestamp), { addSuffix: true })

  const typeConfig: Record<string, { label: string; color: string }> = {
    AGENT_PLANNING_STARTED: { label: 'PLANNING', color: 'text-blue-400 bg-blue-500/10' },
    AGENT_PLANNING_COMPLETED: { label: 'PLANNING', color: 'text-blue-400 bg-blue-500/10' },
    CONTENT_GENERATED: { label: 'GENERATED', color: 'text-emerald-400 bg-emerald-500/10' },
    CONTENT_REGENERATED: { label: 'REGENERATED', color: 'text-amber-400 bg-amber-500/10' },
    BRAND_UPDATED: { label: 'SETTINGS', color: 'text-violet-400 bg-violet-500/10' },
  }

  const config = typeConfig[log.type] || { label: log.type, color: 'text-[#a1a1aa] bg-[#27272a]' }

  return (
    <div className="px-5 py-4 hover:bg-[#111113] transition-colors group flex gap-4">
      <div className="text-xs text-[#52525b] w-[78px] shrink-0 pt-0.5 tabular-nums">{time}</div>

      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2 mb-1">
          <span className={`text-[10px] font-medium px-2 py-px rounded ${config.color}`}>
            {config.label}
          </span>
          <span className="text-sm text-[#f4f4f5] group-hover:text-white transition-colors">
            {log.summary}
          </span>
        </div>

        {log.details && (
          <div className="text-xs text-[#71717a] pl-1 line-clamp-2">
            {log.details.reasoning || log.details.trigger || 'Details available in full log'}
          </div>
        )}
      </div>
    </div>
  )
}

'use client'

import { useEffect, useState } from 'react'
import { Eye, EyeOff, Key, Loader2, Shield, Trash2, Zap } from 'lucide-react'
import { toast } from 'sonner'
import { PageHeader } from '@/components/dashboard/PageHeader'
import { AI_PROVIDERS } from '@/lib/constants/ai-providers'
import type { AIProvider } from '@/lib/agent/types'

interface ProviderStatus {
  id: AIProvider
  label: string
  configured: boolean
  source: 'env' | 'database' | null
  masked: string | null
}

interface SettingsData {
  activeProvider: AIProvider
  monthlyBudgetUsd: number | null
  providers: ProviderStatus[]
}

export default function SettingsPage() {
  const [settings, setSettings] = useState<SettingsData | null>(null)
  const [keys, setKeys] = useState<Partial<Record<AIProvider, string>>>({})
  const [showKey, setShowKey] = useState<Partial<Record<AIProvider, boolean>>>({})
  const [savingProvider, setSavingProvider] = useState<AIProvider | null>(null)
  const [testingProvider, setTestingProvider] = useState<AIProvider | null>(null)

  async function load() {
    const res = await fetch('/api/settings')
    if (res.ok) setSettings(await res.json())
  }

  useEffect(() => {
    load()
  }, [])

  async function saveKey(provider: AIProvider) {
    const apiKey = keys[provider]?.trim()
    if (!apiKey) {
      toast.error('Enter an API key')
      return
    }
    setSavingProvider(provider)
    try {
      const res = await fetch('/api/settings', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ provider, apiKey }),
      })
      if (!res.ok) throw new Error('Save failed')
      setKeys((k) => ({ ...k, [provider]: '' }))
      setSettings(await res.json())
      toast.success(`${provider} API key saved`)
    } catch {
      toast.error('Failed to save API key')
    } finally {
      setSavingProvider(null)
    }
  }

  async function removeKey(provider: AIProvider) {
    if (!confirm(`Remove stored ${provider} API key?`)) return
    try {
      const res = await fetch(`/api/settings?provider=${provider}`, { method: 'DELETE' })
      if (!res.ok) throw new Error('Remove failed')
      setSettings(await res.json())
      toast.success('API key removed')
    } catch {
      toast.error('Failed to remove key')
    }
  }

  async function setActive(provider: AIProvider) {
    const res = await fetch('/api/settings', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ activeProvider: provider }),
    })
    if (res.ok) {
      setSettings(await res.json())
      toast.success(`Active provider set to ${provider}`)
    }
  }

  async function testConnection(provider: AIProvider) {
    setTestingProvider(provider)
    try {
      const res = await fetch('/api/ai/test', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ provider }),
      })
      const data = await res.json()
      if (!res.ok) throw new Error(data.error)
      toast.success(`Connected to ${provider} (${data.model})`)
    } catch (err: unknown) {
      toast.error(err instanceof Error ? err.message : 'Connection failed')
    } finally {
      setTestingProvider(null)
    }
  }

  return (
    <div className="max-w-3xl mx-auto px-8 py-8">
      <PageHeader
        eyebrow="CONFIGURATION"
        title="Settings"
        description="Multi-provider AI configuration. Keys are encrypted at rest and never returned in full."
      />

      {settings && (
        <div className="mb-6 card p-4 flex items-center gap-3">
          <Zap className="w-5 h-5 text-blue-400" />
          <div className="text-sm">
            Active provider:{' '}
            <span className="font-medium text-[#f4f4f5]">{settings.activeProvider}</span>
          </div>
        </div>
      )}

      <div className="space-y-6">
        {AI_PROVIDERS.map((config) => {
          const status = settings?.providers.find((p) => p.id === config.id)
          const isActive = settings?.activeProvider === config.id
          return (
            <div key={config.id} className="card p-6 space-y-4">
              <div className="flex items-start justify-between gap-4">
                <div className="flex items-start gap-4">
                  <div className="w-10 h-10 rounded-xl bg-blue-500/10 flex items-center justify-center shrink-0">
                    <Key className="w-5 h-5 text-blue-400" />
                  </div>
                  <div>
                    <div className="font-medium">{config.label}</div>
                    <p className="text-sm text-[#71717a]">{config.description}</p>
                    {status?.configured && (
                      <div className="flex items-center gap-2 text-xs text-[#a1a1aa] mt-2">
                        <Shield className="w-3.5 h-3.5 text-emerald-400" />
                        via {status.source}
                        {status.masked && (
                          <span className="font-mono text-[#52525b]">{status.masked}</span>
                        )}
                      </div>
                    )}
                  </div>
                </div>
                <button
                  onClick={() => setActive(config.id)}
                  className={`btn h-8 px-3 text-xs ${isActive ? 'btn-primary' : 'btn-secondary'}`}
                >
                  {isActive ? 'Active' : 'Set active'}
                </button>
              </div>

              <div className="flex gap-2">
                <div className="relative flex-1">
                  <input
                    type={showKey[config.id] ? 'text' : 'password'}
                    value={keys[config.id] || ''}
                    onChange={(e) =>
                      setKeys((k) => ({ ...k, [config.id]: e.target.value }))
                    }
                    placeholder={config.keyPlaceholder}
                    className="input w-full pr-10 font-mono text-sm"
                    autoComplete="off"
                  />
                  <button
                    type="button"
                    onClick={() =>
                      setShowKey((s) => ({ ...s, [config.id]: !s[config.id] }))
                    }
                    className="absolute right-3 top-1/2 -translate-y-1/2 text-[#71717a]"
                  >
                    {showKey[config.id] ? (
                      <EyeOff className="w-4 h-4" />
                    ) : (
                      <Eye className="w-4 h-4" />
                    )}
                  </button>
                </div>
                <button
                  onClick={() => saveKey(config.id)}
                  disabled={savingProvider === config.id || !keys[config.id]?.trim()}
                  className="btn btn-primary h-[42px] px-5 disabled:opacity-60"
                >
                  {savingProvider === config.id ? (
                    <Loader2 className="w-4 h-4 animate-spin" />
                  ) : (
                    'Save'
                  )}
                </button>
                <button
                  onClick={() => testConnection(config.id)}
                  disabled={testingProvider === config.id}
                  className="btn btn-secondary h-[42px] px-4"
                >
                  {testingProvider === config.id ? (
                    <Loader2 className="w-4 h-4 animate-spin" />
                  ) : (
                    'Test'
                  )}
                </button>
              </div>

              {status?.configured && status.source === 'database' && (
                <button
                  onClick={() => removeKey(config.id)}
                  className="btn btn-ghost text-red-400 text-sm flex items-center gap-2"
                >
                  <Trash2 className="w-4 h-4" />
                  Remove stored key
                </button>
              )}

              <p className="text-[11px] text-[#52525b]">
                Get a key at{' '}
                <a
                  href={config.keyUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="text-blue-400 hover:underline"
                >
                  {config.keyUrl.replace('https://', '')}
                </a>
              </p>
            </div>
          )
        })}
      </div>
    </div>
  )
}

import { NextRequest, NextResponse } from 'next/server'
import { prisma } from '@/lib/db/prisma'

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url)
  const limit = parseInt(searchParams.get('limit') || '50', 10)
  const offset = parseInt(searchParams.get('offset') || '0', 10)
  const type = searchParams.get('type') || undefined

  try {
    const where = type ? { type: type as any } : {}

    const [logs, total] = await Promise.all([
      prisma.activityLog.findMany({
        where,
        orderBy: { timestamp: 'desc' },
        take: limit,
        skip: offset,
        include: {
          contentItem: {
            select: {
              id: true,
              platform: true,
              format: true,
              title: true,
            },
          },
        },
      }),
      prisma.activityLog.count({ where }),
    ])

    return NextResponse.json({
      logs,
      total,
      hasMore: offset + limit < total,
    })
  } catch (error) {
    console.error('Failed to fetch activity logs:', error)
    return NextResponse.json({ error: 'Failed to load activity history' }, { status: 500 })
  }
}

import { NextResponse } from 'next/server'
import { runPlanningCycle } from '@/lib/agent/orchestrator'

export async function POST() {
  let lastError: any = null

  for (let attempt = 1; attempt <= 2; attempt++) {
    try {
      const result = await runPlanningCycle('manual')
      return NextResponse.json({
        success: true,
        message: attempt === 1 ? 'Planning cycle completed' : `Planning cycle completed after ${attempt} attempts`,
        ...result,
      })
    } catch (error: any) {
      lastError = error
      console.error(`Agent run attempt ${attempt} failed:`, error.message)
      const isRetryable = error.message?.includes('invalid plan structure') || error.message?.includes('Failed to parse JSON') || error.message?.includes('ZodError')
      if (!isRetryable || attempt === 2) break
      await new Promise(resolve => setTimeout(resolve, 800))
    }
  }

  return NextResponse.json({ success: false, error: lastError?.message || 'Failed to run planning cycle', hint: 'The agent had trouble generating valid output. This can happen with complex context. Try again in a moment.' }, { status: 500 })
}
